ALTER TABLE engagements ADD COLUMN IF NOT EXISTS lab_only BOOLEAN DEFAULT FALSE;
ALTER TABLE scan_jobs ADD COLUMN IF NOT EXISTS module_type TEXT;
CREATE INDEX IF NOT EXISTS idx_scan_jobs_module ON scan_jobs(module_type);
ALTER TABLE scope_rules DROP CONSTRAINT IF EXISTS scope_rules_scope_type_check;
ALTER TABLE scope_rules ADD CONSTRAINT scope_rules_scope_type_check CHECK (scope_type IN ('domain','subdomain_wildcard','ip','cidr','web_app','api','environment','wifi_lab','subnet_lab'));
SELECT column_name FROM information_schema.columns WHERE table_name='engagements' AND column_name='lab_only';
